/* Return the largest sum of any contiguous subarray in the vector x.
   This implementation uses Kadane's algorithm (O(n)) for maximum speed
   while preserving the exact semantics of the original double-loop
   solution, including handling all-negative input correctly. */
int maximumSubarray(std::vector<int> const& x) {
    int best = std::numeric_limits<int>::lowest();
