void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();
    // Parallelise with OpenMP; the loop is trivially parallel
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        int val = x[i];
        // Preserve the exact behaviour of the original transform:
        // even numbers (including zero and negative even) are halved,
        // odd numbers (including negative odd) are negated.
        if ((val & 1) == 0) {           // even test faster than val % 2 == 0
            x[i] = val / 2;
        } else {
            x[i] = -val;
        }
    }
