#include <cstddef>
#include <omp.h>

/* Compute the highest node degree in the undirected graph.
 *  A is an NxN adjacency matrix stored in row-major order.
 */
inline int maxDegree(std::vector<int> const& A, size_t N) {
    int highestDegree = 0;

    #pragma omp parallel for
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(N); ++i) {
        int degree = 0;
        const int* row = A.data() + i * N;

        // Process in chunks of 8 for better cache use (unroll 8)
        size_t j = 0;
        for (; j + 8 <= N; j += 8) {
            degree += row[j]   + row[j+1] + row[j+2] + row[j+3]
                    + row[j+4] + row[j+5] + row[j+6] + row[j+7];
        }
        // Tail handling
        for (; j < N; ++j) {
            degree += row[j];
        }

        // Atomically update the global maximum using a reduction
        #pragma omp atomic
        if (degree > highestDegree) highestDegree = degree;
    }
    return highestDegree;
}
