/* Compute the reverse prefix sum (suffix sum) of the vector `x` into `output`.
   Example:
   input : [1, 7, 4, 6, 6, 2]
   output: [2, 8, 14, 18, 25, 26]
*/
inline void reversePrefixSum(const std::vector<int>& x, std::vector<int>& output)
{
    const std::size_t n = x.size();
    if (output.size() != n) output.resize(n);

    if (n == 0) return;

