inline void pixelCounts(std::vector<int> const& image, std::array<size_t, 256> &bins) {
    constexpr int N = 256;
    // initialize bins to zero
    std::fill(bins.begin(), bins.end(), 0);

    // number of available threads
    int nthreads = omp_get_max_threads();

    // each thread owns its own local bin array
    std::vector<std::array<size_t, N>> local_bins(nthreads);
    for (auto &b : local_bins) std::fill(b.begin(), b.end(), 0);

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto &my_bins = local_bins[tid];

        #pragma omp for schedule(static)
        for (size_t i = 0; i < image.size(); ++i) {
            int val = image[i];
            my_bins[val] += 1;
        }
    }

    // merge local bins into the result
    for (int t = 0; t < nthreads; ++t) {
        const auto &src = local_bins[t];
        for (int v = 0; v < N; ++v) {
            bins[v] += src[v];
        }
    }
}
