```cpp
#pragma once
#include <vector>
#include <deque>
#include <limits>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A. A is N×N, row-major. The graph is assumed
   to be connected and undirected.  */
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // Use a byte per vertex for visited/distances (dist == -1 ⇒ not visited)
    std::vector<int8_t> dist(N, -1);
    std::deque<int> q;

    dist[source] = 0;
    q.push_back(source);

    while (!q.empty()) {
        int u = q.front();
        q.pop_front();

        if (u == dest) {
            return static_cast<int>(dist[u]);
        }

        const int base = static_cast<int>(u * N);
        int d = dist[u] + 1;
        for (int v = 0; v < static_cast<int>(N); ++v) {
            if (A[base + v] && dist[v] == -1) {
                dist[v] = d;
                q.push_back(v);
            }
        }
    }

    return std::numeric_limits<int>::max();  // unreachable (should not happen)
}
