struct COOElement {
    std::size_t row, column;
    double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N.
   Example:
   input: alpha=0.5 beta=1.0 A=[{0,1,3}, {1,0,-1}] x=[-4, 2] y=[-1,1]
   output: y=[2, 3]
*/
void spmv(double alpha,
          const std::vector<COOElement>& A,
          const std::vector<double>& x,
          double beta,
          std::vector<double>& y,
          std::size_t M,
          std::size_t N) {
    // scale y by beta
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    // accumulate alpha*A*x into y
    #pragma omp parallel for schedule(dynamic)
    for (std::size_t idx = 0; idx < A.size(); ++idx) {
        const COOElement& a_ij = A[idx];
        if (a_ij.row < M && a_ij.column < N) {
            double prod = alpha * a_ij.value * x[a_ij.column];
#pragma omp atomic
            y[a_ij.row] += prod;
        }
    }
}
