06_fft_dft:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstring>
#include <omp.h>

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

/* Compute the discrete Fourier transform of x.
   For better performance:
   - pre‑compute the cosine/sine table
   - use separate real/imag accumulators
   - parallelise the outer k‑loop with OpenMP
*/
inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output) {
    const int N = static_cast<int>(x.size());
    output.resize(N);

    /* Pre‑compute twiddle factors: cos(2πnk/N) and sin(2πnk/N) */
    std::vector<double> cos_tbl(N * N);
    std::vector<double> sin_tbl(N * N);
    for (int n = 0; n < N; ++n) {
        for (int k = 0; k < N; ++k) {
            double angle = 2.0 * M_PI * n * k / static_cast<double>(N);
            cos_tbl[n * N + k] = std::cos(angle);
            sin_tbl[n * N + k] = std::sin(angle);
        }
    }

    /* Parallel outer loop: each k is independent */
#pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        double real = 0.0, imag = 0.0;
        for (int n = 0; n < N; ++n) {
            double c_real = cos_tbl[n * N + k];
            double c_imag = -sin_tbl[n * N + k];   // negative because of e^{-iθ}
            double xn = x[n];
            real += xn * c_real;
            imag += xn * c_imag;
        }
        output[k] = std::complex<double>(real, imag);
    }
}
