#pragma once
#include <vector>

/*
 * Return the product of the vector x with every odd indexed element inverted.
 * i.e. x0 * 1/x1 * x2 * 1/x3 * ...
 *
 * Example:
 *   input: [4, 2, 10, 4, 5]
 *   output: 25
 */
inline double productWithInverses(const std::vector<double> &x) {
    const size_t n = x.size();
    double prod = 1.0;

    /* Manual loop unrolling for better ILP on x86‑64 */
    size_t i = 0;
    for (; i + 7 < n; i += 8) {
        prod *=  x[i]   * (1.0 / x[i+1]) *
                    x[i+2] * (1.0 / x[i+3]) *
                    x[i+4] * (1.0 / x[i+5]) *
                    x[i+6] * (1.0 / x[i+7]);
    }
    for (; i < n; ++i) {
        prod *= (i & 1) ? (1.0 / x[i]) : x[i];
    }

    return prod;
}
