#include <cstddef>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

/*
 * Count the number of points in each cartesian quadrant.
 *
 * The result is stored in `bins`, where:
 *   bins[0] –  x >= 0 && y >= 0   (first quadrant)
 *   bins[1] –  x <  0 && y >= 0   (second quadrant)
 *   bins[2] –  x <  0 && y <  0   (third quadrant)
 *   bins[3] –  x >= 0 && y <  0   (fourth quadrant)
 *
 * The function is thread‑safe and uses OpenMP to parallelise the
 * loop when the library is compiled with -fopenmp.
 */
inline void countQuadrants(const std::vector<Point>& points,
                           std::array<std::size_t, 4>& bins)
{
    // Initialise the output array to zero.
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Guard against empty input (OpenMP will then spawn no threads).
    if (points.empty()) return;

    // OpenMP parallel loop with reduction to avoid race conditions.
    #pragma omp parallel for reduction(+:bins[0],bins[1],bins[2],bins[3]) schedule(static)
    for (std::size_t i = 0; i < points.size(); ++i) {
        const double x = points[i].x;
        const double y = points[i].y;

        // Convert the two sign tests into integer masks:
        //   0x0 -> both non‑negative
        //   0x4 -> x negative, y non‑negative
        //   0x7 -> both negative
        //   0x3 -> x non‑negative, y negative
        const unsigned int mask = static_cast<unsigned int>((x < 0) << 2 | (y < 0));

        // Add one to the appropriate bin.
        switch (mask) {
            case 0x0: ++bins[0]; break;
            case 0x4: ++bins[1]; break;
            case 0x7: ++bins[2]; break;
            case 0x3: ++bins[3]; break;
            default: /* unreachable */ break;
        }
    }
}
