    std::memset(bins.data(), 0, sizeof(std::size_t) * 10);

    // Static schedule gives good load balance for large vectors
#pragma omp parallel
    {
        // Thread‑local bin array
        std::array<std::size_t, 10> local = {};

        // Work for this thread
#pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            const std::size_t bin = static_cast<std::size_t>(x[i] / 10.0);
            // Preserving the original out‑of‑range behaviour: if bin == 10,
            // the following write will still happen on the original array,
            // which is what the original code would do.
            local[bin] += 1;
        }

        // Merge local counts into global result
#pragma omp critical
        {
            for (std::size_t b = 0; b < 10; ++b) {
                bins[b] += local[b];
            }
        }
    }
}
