void firstLetterCounts(const std::vector<std::string> &s, std::array<size_t, 26> &bins) {
    // Clear the output array (assumed to be uninitialised on entry)
    for (size_t i = 0; i < 26; ++i) bins[i] = 0;

    const int n_threads = omp_get_max_threads();
    // Create a private counter for each thread
    std::vector<std::array<size_t, 26>> local_bins(n_threads);
    for (int th = 0; th < n_threads; ++th) {
        for (size_t i = 0; i < 26; ++i) local_bins[th][i] = 0;
    }

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < s.size(); ++i) {
        const int th = omp_get_thread_num();
        const char c = s[i].front();           // assume non‑empty and lowercase
        const int index = c - 'a';
        if (index >= 0 && index < 26) {
            local_bins[th][index] += 1;
        }
    }

    // Merge thread local counters into the result
    for (int th = 0; th < n_threads; ++th) {
        for (size_t i = 0; i < 26; ++i) {
            bins[i] += local_bins[th][i];
        }
    }
}
