/* Count the number of doubles in the vector x that have a fractional part
   in [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1). Store the counts in `bins`.
   The implementation preserves the exact semantic behaviour of the original code,
   but is spatially and temporally optimised for modern x86‑64 CPUs
   (8 threads, gcc ‑O2 with OpenMP).
*/
void countQuartiles(const std::vector<double>& x, std::array<std::size_t, 4>& bins)
{
    const std::size_t n = x.size();
    if (n == 0) {
        bins = {0, 0, 0, 0};
        return;
    }

    // 4 thread‑private accumulators to avoid atomic operations
    const int numThreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 4>> localBins(numThreads);
    for (int t = 0; t < numThreads; ++t) {
        localBins[t] = {0, 0, 0, 0};
    }

#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::array<std::size_t, 4>& lb = localBins[tid];

#pragma omp for schedule(static)
        for (std::size_t i = 0; i < n; ++i) {
            const double val   = x[i];
            // fast fractional part: val - trunc(val)
            const double frac  = val - std::trunc(val);
            if (frac < 0.25)      ++lb[0];
            else if (frac < 0.5)  ++lb[1];
            else if (frac < 0.75) ++lb[2];
            else                  ++lb[3];
        }
    }

    // reduce thread‑local bins into the final result
    bins[0] = bins[1] = bins[2] = bins[3] = 0;
    for (const auto& lb : localBins) {
        bins[0] += lb[0];
        bins[1] += lb[1];
        bins[2] += lb[2];
        bins[3] += lb[3];
    }
}
