#pragma once
#include <vector>
#include <algorithm>
#include <numeric>
#include <omp.h>

int largestComponent(const std::vector<int>& A, size_t N) {
    // Union–Find data structures
    std::vector<int> parent(N);
    std::vector<int> sz(N, 1);
    std::iota(parent.begin(), parent.end(), 0);

    auto find = [&](auto self, int x) -> int {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]]; // path compression
            x = parent[x];
        }
        return x;
    };

    // Parallel union operation over the upper‑triangular part of the matrix
    #pragma omp parallel for schedule(static)
    for (long long idx = 0; idx < static_cast<long long>(N) * (N - 1) / 2; ++idx) {
        long long i = (long long)(sqrt(1 + 8*idx + 1) - 1) / 2;
        long long j = idx - i * (i + 1) / 2;
        if (A[i * N + j] == 1) {
            int a = find(find, static_cast<int>(i));
            int b = find(find, static_cast<int>(j));
            if (a == b) continue;
            // Simple union by size
            if (sz[a] < sz[b]) std::swap(a, b);
            parent[b] = a;
            sz[a] += sz[b];
        }
    }

    // Compute component sizes
    std::vector<int> compSize(N, 0);
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        int root = find(find, i);
        #pragma omp atomic
        compSize[root] += 1;
    }

    return *std::max_element(compSize.begin(), compSize.end());
}
