#pragma once
#include <vector>
#include <cstdint>
#include <cstddef>
#include <omp.h>

/*
 * Compute the inclusive prefix sum of the input vector `x` into `output`.
 * The function is fully parallelized using OpenMP and preserves the exact
 * behaviour of std::inclusive_scan.
 *
 * Example:
 *   input:  [1, 7, 4, 6, 6, 2]
 *   output: [1, 8,12,18,24,26]
 */
inline void prefixSum(const std::vector<int64_t> &x, std::vector<int64_t> &output)
{
    const std::size_t n = x.size();
    if (n == 0) return;

    // Ensure output is the correct size
    output.resize(n);

    /* 1. Copy input to output (so each thread can work on its own block) */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i)
        output[i] = x[i];

    /* 2. Determine block size (number of elements per thread) */
    const int num_threads = omp_get_max_threads();
    const std::size_t block = (n + num_threads - 1) / num_threads;   // ceil

    /* 3. Compute the sum of each block in parallel. */
    std::vector<int64_t> block_sums(num_threads, 0);
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * block;
        const std::size_t end   = std::min(start + block, n);

        int64_t sum = 0;
        for (std::size_t i = start; i < end; ++i) {
            sum += output[i];
            output[i] = sum + (i > 0 ? output[i - 1] - output[i] : 0);
        }
        block_sums[tid] = sum;
    }

    /* 4. Compute the prefix sums of the block sums sequentially. */
    int64_t offset = 0;
    for (int i = 0; i < static_cast<int>(block_sums.size()); ++i) {
        int64_t tmp = block_sums[i];
        block_sums[i] = offset;
        offset += tmp;
    }

    /* 5. Add the offset to each element in the corresponding block. */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i)
        output[i] += block_sums[i / block];
}
