/* Compute one iteration of a 3-point 1D Jacobi stencil on `input`.
   Each element of `input` will be averaged with its two neighbors
   and stored in the corresponding element of `output`.
   i.e. output[i] = (input[i-1] + input[i] + input[i+1]) / 3
   Replace with 0 when reading past the boundaries of `input`. */
inline void jacobi1D(std::vector<double> const& input, std::vector<double>& output) {
    const std::size_t n = input.size();
    if (n == 0) return;

    // Ensure output has the same size as input
    output.resize(n);

    // Pointers for faster access
    const double* in  = input.data();
    double*       out = output.data();

    // Parallel loop
    #pragma omp parallel for schedule(static, 1024)
    for (long long i = 0; i < static_cast<long long>(n); ++i) {
        const double left  = (i > 0) ? in[i-1] : 0.0;
        const double right = (i+1 < static_cast<long long>(n)) ? in[i+1] : 0.0;
        out[i] = (left + in[i] + right) / 3.0;
    }
}
