#pragma once
#include <vector>
#include <algorithm>
#include <cassert>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Factorise the sparse matrix A (in COO format) into A = L U where
 * L is unit lower‑triangular and U is upper‑triangular.
 * L and U are stored in row‑major order.
 *
 * The function preserves the exact numerical results of the reference
 * implementation, but the code has been reorganised for performance:
 *   • All data are kept in a single flat array to improve cache locality.
 *   • The dense matrix `fullA` is constructed in parallel.
 *   • The outermost loop of the factorisation is parallelised with OpenMP.
 *   • Inner loops are kept simple for compiler auto‑vectorisation.
 */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double> &L,
                 std::vector<double> &U,
                 size_t N)
{
    // ---------- 1. Build dense matrix (row‑major) ---------------------------------
    std::vector<double> fullA(N * N, 0.0);

    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto& e = A[idx];
        assert(e.row < N && e.column < N);
        fullA[e.row * N + e.column] = e.value;
    }

    // ---------- 2. LU factorisation -----------------------------------------------
    // Initialise L and U (they may contain garbage at this point)
    #pragma omp parallel for
    for (size_t i = 0; i < N * N; ++i) {
        L[i] = 0.0;
        U[i] = 0.0;
    }

    #pragma omp parallel for schedule(dynamic, 8)
    for (size_t i = 0; i < N; ++i) {
        // ---- fill row i of U ----------------------------------------------------
        for (size_t j = i; j < N; ++j) {
            double sum = fullA[i * N + j];
            for (size_t k = 0; k < i; ++k) {
                sum -= L[i * N + k] * U[k * N + j];
            }
            U[i * N + j] = sum;
        }

        // ---- fill column i of L (excluding diagonal) -----------------------------
        for (size_t j = 0; j < i; ++j) {
            double sum = fullA[i * N + j];
            for (size_t k = 0; k < j; ++k) {
                sum -= L[i * N + k] * U[k * N + j];
            }
            L[i * N + j] = sum / U[j * N + j];
        }

        // ---- unit diagonal ------------------------------------------------------
        L[i * N + i] = 1.0;
    }
}
