double closestPair(std::vector<double> const& x) {
    // At least two elements are required
    if (x.size() < 2) {
        return 0.0;
    }

    // Make a modifiable copy and sort it
    std::vector<double> sorted = x;
    std::sort(sorted.begin(), sorted.end());

    // Find the minimum distance between any two consecutive elements
    // in the sorted order. Use OpenMP reduction for speed.
    double minDist = std::numeric_limits<double>::max();

    #pragma omp parallel for reduction(min:minDist) schedule(static)
    for (std::size_t i = 1; i < sorted.size(); ++i) {
        double d = sorted[i] - sorted[i - 1];
        if (d < minDist) {
            minDist = d;
        }
    }

    return minDist;
