#pragma once
#include <vector>
#include <omp.h>
#include <unordered_map>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Parallel sparse matrix–matrix multiplication: Y = A * X
 * A  : M × K sparse matrix in COO format
 * X  : K × N sparse matrix in COO format
 * Y  : M × N dense matrix (row-major)
 *
 * The function preserves the original semantics while exploiting
 * parallelism and reducing the number of expensive comparisons.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M,
          size_t K,
          size_t N)
{
    // initialise all entries of Y to 0
    Y.assign(M * N, 0.0);

    /*---------- Build auxiliary map for fast look‑up ------------------*/
    // map from a column index of A (which is a row index in X) to the
    // list of non‑zeros in X that share that index.
    std::vector<std::vector<COOElement>> X_by_row(K);
    for (auto const& e : X) {
        if (e.row < K) {                // sanity check
            X_by_row[e.row].push_back(e);
        }
    }

    /*---------- Parallel block ---------------------------------------*/
    const int nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> localY(nthreads, std::vector<double>(M * N, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto& myY = localY[tid];

        #pragma omp for schedule(static)
        for (size_t i = 0; i < A.size(); ++i) {
            const auto& a = A[i];
            if (a.column >= K) continue;          // out of range, skip

            const auto& vecX = X_by_row[a.column];
            if (vecX.empty()) continue;

            for (auto const& x : vecX) {
                if (x.row == a.column) {          // safety check
                    myY[a.row * N + x.column] += a.value * x.value;
                }
            }
        }
    }

    /*---------- Reduce per‑thread results into Y ---------------------*/
    for (int t = 0; t < nthreads; ++t) {
        const auto& myY = localY[t];
        for (size_t idx = 0; idx < Y.size(); ++idx) {
            Y[idx] += myY[idx];
        }
    }
}
