```cpp
#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Solve the sparse linear system Ax = b for x.
 * A is a sparse N×N matrix in COO format. x and b are dense vectors with N elements.
 * The function preserves the exact output of the original implementation.
 */
inline void solveLinearSystem(std::vector<COOElement> const& A,
                               std::vector<double> const&    b,
                               std::vector<double> &         x,
                               size_t const                  N)
{
    /* Allocate a flat matrix of size N×N for cache friendliness */
    std::vector<double> matrix(N * N, 0.0);

    /* Fill the matrix with the COO entries */
    for (auto const& e : A)
        matrix[e.row * N + e.column] = e.value;

    /* Copy RHS and allocate solution vector */
    std::vector<double> rhs = b;
    x.assign(N, 0.0);

    /* =============================== */
    /* Gaussian elimination with partial pivoting */
    /* =============================== */
    for (size_t i = 0; i < N; ++i) {
        /* ----- pivot search ----- */
        size_t pivotRow = i;
        double maxVal   = std::abs(matrix[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxVal) {
                maxVal   = val;
                pivotRow = k;
            }
        }

        /* ----- swap rows i and pivotRow ----- */
        if (pivotRow != i) {
            for (size_t k = i; k < N; ++k) {
                std::swap(matrix[i * N + k], matrix[pivotRow * N + k]);
            }
            std::swap(rhs[i], rhs[pivotRow]);
        }

        /* ----- eliminate rows below ----- */
        double const pivotVal = matrix[i * N + i];
        /* We can parallelise the inner loops with OpenMP SIMD directives */
        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double const factor = -matrix[k * N + i] / pivotVal;
            size_t const baseK   = k * N;
            size_t const baseI   = i * N;
            /* Set the leading element to zero */
            matrix[baseK + i] = 0.0;
            /* Update the rest of the row */
            for (size_t j = i + 1; j < N; ++j) {
                matrix[baseK + j] += factor * matrix[baseI + j];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    /* =============================== */
    /* Back‑substitution */
    /* =============================== */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double const div = rhs[i] / matrix[i * N + i];
        x[i] = div;
        for (int k = i - 1; k >= 0; --k) {
            rhs[k] -= matrix[k * N + i] * div;
        }
    }
}
