#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/* Set every cell's value to 1 if it has exactly one neighbor that's a 1. Otherwise set it to 0.
   input and output are NxN grids laid out in row-major order.
   The original semantics are preserved exactly.
*/
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     size_t N)
{
    const int* in = input.data();          // raw pointer to input
    int* out = output.data();              // raw pointer to output

    // Parallelize over the flattened indices
    #pragma omp parallel for schedule(static)
    for (size_t k = 0; k < N * N; ++k) {
        size_t i = k / N;
        size_t j = k % N;

        // Count 1‑valued neighbors (up, down, left, right)
        int cnt = 0;
        if (i > 0      && in[(i-1)*N + j] == 1) ++cnt; // up
        if (i + 1 < N  && in[(i+1)*N + j] == 1) ++cnt; // down
        if (j > 0      && in[i*N + j-1] == 1) ++cnt;    // left
        if (j + 1 < N  && in[i*N + j+1] == 1) ++cnt;    // right

        out[k] = (cnt == 1) ? 1 : 0;
    }
}
