                    xi * (yj - ys[k]) +
                    xj * (ys[k] - yi) +
                    xs[k] * (yi - yj)
                ) * 0.5;
                if (area < global_min) global_min = area;
                /* short‑circuit: zero area is the absolute minimum */
                if (global_min == 0.0) goto finished;
            }
        }
