#pragma once
#include <vector>
#include <algorithm>

struct Point {
    double x, y;
};

static inline double cross(const Point &a, const Point &b, const Point &c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point> &points, std::vector<Point> &hull) {
    const size_t n = points.size();
    if (n < 3) {                     // trivial cases
        hull = points;
        return;
    }

    // --- 1. Sort points lexicographically by (x, y) -----------------------
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point &a, const Point &b) noexcept {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // --- 2. Build lower and upper chains -----------------------------------
    std::vector<Point> buf(2 * n);    // temporary buffer for the hull
    size_t k = 0;                    // number of points in buf

    // Lower hull
    for (size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(buf[k - 2], buf[k - 1], sorted[i]) <= 0) {
            --k;
        }
        buf[k++] = sorted[i];
    }

    // Upper hull
    size_t t = k + 1;                // start index for the upper hull
    for (size_t i = n; i-- > 0;) {
        while (k >= t && cross(buf[k - 2], buf[k - 1], sorted[i]) <= 0) {
            --k;
        }
        buf[k++] = sorted[i];
    }

    // --- 3. Finalize hull --------------------------------------------------
    buf.resize(k - 1);               // remove duplicated first/last point
    hull.swap(buf);                  // efficient transfer of data
}
