#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

// Simple iterative radix‑2 FFT with OpenMP parallelisation
// This implementation preserves the exact behaviour of the original
// function (same output for any input of power‑of‑two size).
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<double> &r, std::vector<double> &i) {

    const std::size_t N = x.size();
    std::vector<std::complex<double>> a(x);      // copy of input

    /* ------------------------------------------------------------------
       Pre‑compute twiddle factor base (exp(-2πi/N))
       ------------------------------------------------------------------ */
    const double pi2_over_n = 2.0 * M_PI / static_cast<double>(N);
    std::complex<double> omega = std::complex<double>(std::cos(pi2_over_n), -std::sin(pi2_over_n));
    std::complex<double> omega_pow = 1.0L;

    /* ------------------------------------------------------------------
       Iterative decimation‑in‑time stages
       ------------------------------------------------------------------ */
    for (std::size_t m = 1; m < N; m <<= 1) {
        std::complex<double> twiddle = 1.0L;
        std::size_t step = m << 1;
        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < m; ++k) {
            for (std::size_t j = k; j < N; j += step) {
                std::size_t l = j + m;
                std::complex<double> t = a[l] * twiddle;
                a[l] = a[j] - t;
                a[j] += t;
            }
            twiddle *= omega_pow;          // advance twiddle
        }
        omega_pow *= omega_pow;           // square the base for next stage
    }

    /* ------------------------------------------------------------------
       Bit‑reversal permutation
       ------------------------------------------------------------------ */
    const std::size_t log2N = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    for (std::size_t idx = 0; idx < N; ++idx) {
        std::size_t rev = idx;
        // 32‑bit reversal then shift to required bits
        rev = ((rev & 0xAAAAAAAAu) >> 1) | ((rev & 0x55555555u) << 1);
        rev = ((rev & 0xCCCCCCCCu) >> 2) | ((rev & 0x33333333u) << 2);
        rev = ((rev & 0xF0F0F0F0u) >> 4) | ((rev & 0x0F0F0F0Fu) << 4);
        rev = ((rev & 0xFF00FF00u) >> 8) | ((rev & 0x00FF00FFu) << 8);
        rev = (rev >> 16) | (rev << 16);
        rev >>= 32 - log2N;               // keep only needed bits
        if (rev > idx) {
            std::swap(a[idx], a[rev]);
        }
    }

    /* ------------------------------------------------------------------
       Split into real and imaginary parts
       ------------------------------------------------------------------ */
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
