/*
 * Multiply the matrix A by the vector x.
 * A is an MxN matrix stored in row‑major order,
 * x has N elements, and y has M elements.
 */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 std::size_t M, std::size_t N)
{
    // Avoid bounds checks and temporary copies
    const double *a = A.data();
    const double *v = x.data();
    double *r = y.data();

    // Manual loop unrolling (factor 4) – economical for typical sizes
    const std::size_t unroll = 4;

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < M; ++i) {
        const double *ai = a + i * N;
        double acc = 0.0;
        std::size_t j = 0;

        // Vectorised inner loop (unrolled)
        for (; j + unroll - 1 < N; j += unroll) {
            acc += ai[j]     * v[j];
            acc += ai[j + 1] * v[j + 1];
            acc += ai[j + 2] * v[j + 2];
            acc += ai[j + 3] * v[j + 3];
        }
        // Tail case
        for (; j < N; ++j) {
            acc += ai[j] * v[j];
        }
        r[i] = acc;
    }
}
