struct Point {
    double x, y;
};

/* Fast squared distance */
inline double dist2(Point const& a, Point const& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx*dx + dy*dy;
}

/* Euclidean distance, with a branch‑predictable squared‑root */
inline double dist(Point const& a, Point const& b)
{
    return std::sqrt(dist2(a,b));
}

/*
 * Return the perimeter of the smallest convex polygon that
 * contains all the points in the vector `points`.
 *
 * Algorithm: Andrew's monotone chain to compute the convex hull
 * in O(n log n), then a single scan for the perimeter.
 */
double convexHullPerimeter(const std::vector<Point>& points)
{
    if (points.size() < 3) return 0.0;

    /* 1. Sort points lexicographically (x, then y). */
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    const auto cross = [](const Point& o, const Point& a, const Point& b) -> double {
        return (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x);
    };

    /* 2. Build the lower and upper hulls in a single buffer. */
    std::vector<Point> hull(2 * sorted.size());
    int k = 0;                     // current hull size

    for (const Point& p : sorted) {
        while (k >= 2 && cross(hull[k-2], hull[k-1], p) <= 0) --k;
        hull[k++] = p;
    }

    for (size_t i = sorted.size()-1; i > 0; --i) {
        const Point& p = sorted[i-1];
        while (k >= (int)sorted.size() + 1 && cross(hull[k-2], hull[k-1], p) <= 0) --k;
        hull[k++] = p;
    }
    hull.resize(k-1);   // last point equals first one

    /* 3. Compute the perimeter. */
    double peri = 0.0;
    for (size_t i = 0; i < hull.size(); ++i) {
        const Point& a = hull[i];
        const Point& b = hull[(i+1) % hull.size()];
        peri += dist(a, b);
    }
    return peri;
}
