/*
    Optimised Game of Life step.
    - Uses row-major arrays stored in a flat std::vector<int>.
    - Parallelised with OpenMP (collapse allows 2‑D parallelisation).
    - Minor branch reduction and loop unrolling improve cache utilisation.
    - Behaviour is identical to the original implementation.
*/
void gameOfLife(std::vector<int> const& input,
                std::vector<int> &output,
                size_t N) {
    // All indices are 0‑based; treat input & output as 1‑D arrays.
    // The compiler will optimise away the temporary pointer casts.
    const int* in  = input.data();
    int*       out = output.data();

    // Pre‑compute row strides to avoid repeated multiplications.
    const size_t stride = N;

#pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {
            const size_t idx = i * stride + j;
            int sum = 0;

            /* Manually unrolled neighbour look‑ups */
            // North
            if (i > 0)          sum += in[(i - 1) * stride + j];
            // South
            if (i < N - 1)      sum += in[(i + 1) * stride + j];
            // West
            if (j > 0)          sum += in[i * stride + (j - 1)];
            // East
            if (j < N - 1)      sum += in[i * stride + (j + 1)];
            // Northwest
            if (i > 0 && j > 0) sum += in[(i - 1) * stride + (j - 1)];
            // Northeast
            if (i > 0 && j < N - 1) sum += in[(i - 1) * stride + (j + 1)];
            // Southwest
            if (i < N - 1 && j > 0) sum += in[(i + 1) * stride + (j - 1)];
            // Southeast
            if (i < N - 1 && j < N - 1) sum += in[(i + 1) * stride + (j + 1)];

            /* Apply Game of Life rules – a compact, branch‑friendly form */
            const int alive = in[idx];
            int next;
            if (alive) {
                next = (sum == 2 || sum == 3);
            } else {
                next = (sum == 3);
            }
            out[idx] = next;
        }
    }
}
