#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Optimised matrix multiplication:
 *   C = A * B
 *   A MxK, B KxN, C MxN
 *   row‑major storage
 *
 * The implementation is cache‐friendly (blocking) and uses OpenMP
 * parallelism to fully utilise the 8‑thread CPU.
 * It preserves the exact semantics of the original function while
 * significantly reducing runtime on typical architectures.
 */
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Block size tuned for typical L2/L3 cache sizes (64/128/256 bytes)
    constexpr size_t BLOCK_M = 64;
    constexpr size_t BLOCK_K = 64;
    constexpr size_t BLOCK_N = 64;

    // Initialise C to zero if it may contain garbage
    std::fill(C.begin(), C.end(), 0.0);

    // Parallelise over outer blocks of rows of A and columns of B
    #pragma omp parallel for collapse(2) schedule(dynamic, 1)
    for (size_t ii = 0; ii < M; ii += BLOCK_M) {
        for (size_t jj = 0; jj < N; jj += BLOCK_N) {
            for (size_t kk = 0; kk < K; kk += BLOCK_K) {
                // Determine actual block sizes
                size_t i_max = (ii + BLOCK_M <= M) ? BLOCK_M : M - ii;
                size_t j_max = (jj + BLOCK_N <= N) ? BLOCK_N : N - jj;
                size_t k_max = (kk + BLOCK_K <= K) ? BLOCK_K : K - kk;

                // Pointers to current block positions
                const double* a0 = &A[ii * K + kk];
                const double* b0 = &B[kk * N + jj];
                double*       c0 = &C[ii * N + jj];

                for (size_t i = 0; i < i_max; ++i) {
                    const double* a_row = a0 + i * K;
                    double* c_row = c0 + i * N;
                    for (size_t k = 0; k < k_max; ++k) {
                        double a_val = a_row[k];
                        const double* b_col = b0 + k * N;
                        for (size_t j = 0; j < j_max; ++j) {
                            c_row[j] += a_val * b_col[j];
                        }
                    }
                }
            }
        }
    }
}
