static constexpr int edgeKernel[3][3] = {{-1, -1, -1},
                                         {-1,  8, -1},
                                         {-1, -1, -1}};

/* Convolve the edge kernel with a grayscale image.  
 * Each pixel will be replaced with the dot product of itself and its neighbors
 * with the edge kernel.  Pixels outside the image boundaries are treated
 * as zero, and the output is clipped to [0,255].
 *
 * Parameters:
 *   imageIn  - input image, NxN, row-major, values in [0,255]
 *   imageOut - output image, must be pre‑allocated to N*N
 *   N        - dimension of the square image
 */
inline void convolveKernel(const std::vector<int>&  imageIn,
                           std::vector<int>&        imageOut,
                           std::size_t              N) noexcept
{
    // raw pointers for faster indexing
    const int* in  = imageIn.data();
    int*       out = imageOut.data();
    const std::size_t stride = N;

    // Parallelise over the two outer loops (row and column)
    #pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        for (std::size_t j = 0; j < N; ++j) {
            int sum = 0;

            // handle the 3x3 neighbourhood
            // 0   1   2
            // 3   4   5
            // 6   7   8
            for (int ki = -1; ki <= 1; ++ki) {
                const int x = static_cast<int>(i) + ki;
                if (x < 0 || x >= static_cast<int>(N)) continue;
                const int base = x * stride;
                for (int kj = -1; kj <= 1; ++kj) {
                    const int y = static_cast<int>(j) + kj;
                    if (y < 0 || y >= static_cast<int>(N)) continue;
                    sum += in[base + y] * edgeKernel[ki + 1][kj + 1];
                }
            }

            // clip to [0,255]
            out[i * stride + j] = static_cast<int>(std::max(0, std::min(255, sum)));
        }
    }
}
