namespace fft_detail
{
inline std::size_t bit_reverse(std::size_t x, std::size_t logn)
{
    x = ((x & 0xaaaaaaaaaaaaaaaaULL) >> 1) | ((x & 0x5555555555555555ULL) << 1);
    x = ((x & 0xccccccccccccccccULL) >> 2) | ((x & 0x3333333333333333ULL) << 2);
    x = ((x & 0xf0f0f0f0f0f0f0f0ULL) >> 4) | ((x & 0x0f0f0f0f0f0f0f0fULL) << 4);
    x = ((x & 0xff00ff00ff00ff00ULL) >> 8) | ((x & 0x00ff00ff00ff00ffULL) << 8);
    x = ((x & 0xffff0000ffff0000ULL) >> 16) | ((x & 0x0000ffff0000ffffULL) << 16);
    return x >> (64 - logn);
}
} // namespace fft_detail

void fft(std::vector<std::complex<double>> const& x, std::vector<std::complex<double>>& output)
{
    constexpr double PI = 3.141592653589793238462643383279502884;
    std::size_t N = x.size();
    output = x;
    if (N == 0) return;

    // number of stages
    std::size_t logN = std::size_t(std::log2(N));

    // pre‑compute twiddle factors
    std::vector<std::complex<double>> twiddles(N / 2);
    for (std::size_t i = 0; i < N / 2; ++i)
        twiddles[i] = std::polar(1.0, -2 * PI * static_cast<double>(i) / static_cast<double>(N));

    // iterative radix‑2 Cooley–Tukey
    for (std::size_t s = 1; s <= logN; ++s)
    {
        std::size_t m = 1U << s;           // sub‑transform size
        std::size_t half_m = m >> 1;       // half size
        std::size_t step = N / m;          // twiddle step

        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < half_m; ++k)
        {
            std::complex<double> w = twiddles[k * step];
            for (std::size_t j = k; j < N; j += m)
            {
                std::size_t l = j + half_m;
                std::complex<double> t = w * output[l];
                output[l] = output[j] - t;
                output[j] += t;
            }
        }
    }

    // bit‑reversal
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = fft_detail::bit_reverse(i, logN);
        if (j > i)
            std::swap(output[i], output[j]);
    }
}
