#include <cstdint>
#include <omp.h>

static inline double piD() { return 3.141592653589793238462643383279502884L; }

// Pre‑computed bit reverse table for a given N (must be power of two)
static std::vector<uint32_t> make_bitrev(uint32_t N) {
    uint32_t m = 0;
    while ((1U << m) < N) ++m;
    std::vector<uint32_t> rev(N);
    for (uint32_t i = 0; i < N; ++i) {
        uint32_t x = i, r = 0;
        for (uint32_t j = 0; j < m; ++j) {
            r = (r << 1) | (x & 1U);
            x >>= 1;
        }
        rev[i] = r;
    }
    return rev;
}

// Cooley–Tukey batched radix‑2 FFT, in‑place
static void fft_radix2(std::vector<std::complex<double>>& x) {
    const uint32_t N = static_cast<uint32_t>(x.size());
    if (N <= 1) return;

    // Bit‑reversal
    static std::vector<std::vector<uint32_t>> rev_cache;
    static std::mutex cache_mtx;
    {
        std::lock_guard<std::mutex> lk(cache_mtx);
        if (rev_cache.size() <= N) rev_cache.resize(N + 1);
        if (rev_cache[N].empty()) rev_cache[N] = make_bitrev(N);
    }
    const auto& rev = rev_cache[N];
    for (uint32_t i = 0; i < N; ++i) {
        uint32_t j = rev[i];
        if (j > i) std::swap(x[i], x[j]);
    }

    // FFT bodies
    for (uint32_t len = 2; len <= N; len <<= 1) {
        const double angle = -2.0 * piD() / static_cast<double>(len);
        const double wlen_real = std::cos(angle);
        const double wlen_imag = std::sin(angle);

        #pragma omp parallel for schedule(static)
        for (uint32_t i = 0; i < N; i += len) {
            double wr = 1.0, wi = 0.0;
            for (uint32_t j = 0; j < len / 2; ++j) {
                auto u = x[i + j];
                auto v = x[i + j + len / 2] * std::complex<double>(wr, wi);
                x[i + j] = u + v;
                x[i + j + len / 2] = u - v;

                // twiddle multiply
                double tmp_wr = wr * wlen_real - wi * wlen_imag;
                double tmp_wi = wr * wlen_imag + wi * wlen_real;
                wr = tmp_wr;
                wi = tmp_wi;
            }
        }
    }
}

// Public API: performs FFT, bit‑reverse, conjugate
inline void fftConjugate(std::vector<std::complex<double>>& x) {
    fft_radix2(x);
    for (auto& c : x) c = std::conj(c);
}
