/// The ordering of equal elements is preserved (stable sort), matching the
/// behaviour of the original reference implementation.
///
/// @param x         Input vector of float values.
/// @param ranks_    Output vector of the same length as `x` that will hold the
///                  rank of each element. The vector is resized if necessary.
///
void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    const size_t n = x.size();

    // Re‑use `ranks_` to avoid reallocations.
    if (ranks_.size() != n) ranks_.resize(n);

    // 1. Build index array.
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);

    // 2. Stable sort indices according to the values in `x`.
    std::stable_sort(indices.begin(), indices.end(),
                     [&x](size_t i1, size_t i2) { return x[i1] < x[i2]; });

    // 3. Write the rank of each original element.
    //    The loop is short and independent; parallelise with OpenMP.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i) {
        ranks_[ indices[i] ] = i;
    }
}
