 *  input: [{title="Green Eggs and Ham", pages=72},
 *          {title="gulliver's travels", pages=362},
 *          {title="Stories of Your Life", pages=54},
 *          {title="Hamilton", pages=818}]
 *  output: 2
 */
inline size_t findLastShortBook(const std::vector<Book>& books) {
    // Fast return for empty vector
    if (books.empty()) {
        return books.size();   // Same as 0
    }

    const size_t n = books.size();
    size_t best = n;  // sentinel for "not found"

    // Parallel scan: each thread tracks the largest index it found.
    #pragma omp parallel
    {
        size_t local_best = n;
        #pragma omp for nowait
        for (size_t i = 0; i < n; ++i) {
            if (books[i].pages < 100 && i > local_best) {
                local_best = i;
            }
        }
        #pragma omp critical
        {
            if (local_best < best) {
                best = local_best;
            }
        }
    }

    return best;
}
