#pragma once
#include <vector>
#include <cstddef>

/* Factorise A into the (L,U) form in place.
   A is a square NxN matrix stored row‑major. */
inline void luFactorize(std::vector<double> &A, std::size_t N) {
    const std::size_t n = N;           // avoid repeated size() calls
    for (std::size_t k = 0; k < n; ++k) {
        const std::size_t kRow = k * n;
        const double pivot = A[kRow + k];        // save pivot

        /* Each row i > k can be updated independently.
           Hence the inner loop on i can be parallelised safely. */
#pragma omp parallel for schedule(static)
        for (std::size_t i = k + 1; i < n; ++i) {
            const std::size_t iRow = i * n;
            const double factor = A[iRow + k] / pivot;
            A[iRow + k] = factor;                // store L(i,k)

            /* Update the remaining row entry */
            double* restrict row_i = &A[iRow + k + 1];
            const double* restrict row_k = &A[kRow + k + 1];
            const std::size_t remaining = n - k - 1;

            // vectorised loop: process in chunks
            std::size_t j = 0;
            for (; j + 3 < remaining; j += 4) {
                row_i[j]     -= factor * row_k[j];
                row_i[j + 1] -= factor * row_k[j + 1];
                row_i[j + 2] -= factor * row_k[j + 2];
                row_i[j + 3] -= factor * row_k[j + 3];
            }
            for (; j < remaining; ++j) {
                row_i[j] -= factor * row_k[j];
            }
        }
    }
}
