```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <limits>
#include <cmath>
#include <omp.h>

struct Point {
    double x, y;
};

static inline double dist2(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

/* O(n log n) closest pair algorithm.
 * It follows the standard divide‑and‑conquer approach:
 *   1. Sort points by x.
 *   2. Recursively find the minimal distance in left/right halves.
 *   3. Merge step: consider points within strip width sqrt(minDist) around median.
 */
static double closestPairRec(std::vector<Point>& pts, std::vector<Point>& tmp, size_t l, size_t r) {
    if (r - l <= 3) {
        double d2 = std::numeric_limits<double>::max();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j)
                d2 = std::min(d2, dist2(pts[i], pts[j]));
        /* sort by y for merging step */
        std::sort(pts.begin() + l, pts.begin() + r, [](const Point& a, const Point& b){ return a.y < b.y; });
        return d2;
    }

    size_t mid = l + (r - l) / 2;
    double midX = pts[mid].x;

    double d2_left  = closestPairRec(pts, tmp, l, mid);
    double d2_right = closestPairRec(pts, tmp, mid, r);
    double d2 = std::min(d2_left, d2_right);

    /* Merge by y */
    std::merge(pts.begin() + l, pts.begin() + mid,
               pts.begin() + mid, pts.begin() + r,
               tmp.begin(), [](const Point& a, const Point& b){ return a.y < b.y; });
    std::copy(tmp.begin(), tmp.begin() + (r - l), pts.begin() + l);

    /* Build strip */
    std::vector<Point> strip;
    double d = std::sqrt(d2);
    for (size_t i = l; i < r; ++i)
        if (std::abs(pts[i].x - midX) < d)
            strip.push_back(pts[i]);

    /* Compare each point with next up to 7 points */
    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < d; ++j) {
            double d2_candidate = dist2(strip[i], strip[j]);
            if (d2_candidate < d2) {
                d2 = d2_candidate;
                d = std::sqrt(d2);
            }
        }
    }

    return d2;
}

double closestPair(std::vector<Point> const& points) {
    if (points.size() < 2)
        return 0.0;

    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> tmp(pts.size());
    double min_dist2 = closestPairRec(pts, tmp, 0, pts.size());
    return std::sqrt(min_dist2);
}
