#pragma once
#include <vector>
#include <cstddef>
#include <cmath>
#include <omp.h>

/* Compute one iteration of a 5‑point 2‑D Jacobi stencil.
 *
 * Each output element is the average of itself and its four
 * neighbours, treating out‑of‑bounds accesses as 0.
 *
 * Parameters
 * ----------
 * input  : reference to the input grid (row‑major, size N×N)
 * output : reference to the output grid (must be the same size)
 * N      : grid dimension
 */
void jacobi2D(std::vector<double> const& input,
              std::vector<double> &output,
              std::size_t N) noexcept
{
    // Raw pointers for fastest access
    const double* restrict in  = input.data();
    double*       restrict out = output.data();
    const std::size_t stride = N;            // bytes in one row
    const std::size_t tot   = N * N;         // total elements

    // Parallelize the outer loop; each row is completely independent
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t row    = i * stride;          // offset of current row
        const bool       top    = (i > 0);              // has top neighbour
        const bool       bottom = (i + 1 < N);          // has bottom neighbour
        const std::size_t topRow    = (i - 1) * stride; // offset of top row
        const std::size_t bottomRow = (i + 1) * stride; // offset of bottom row

        for (std::size_t j = 0; j < N; ++j) {
            std::size_t idx = row + j;
            double sum = in[idx];                       // centre

            if (top)    sum += in[topRow + j];          // top
            if (bottom) sum += in[bottomRow + j];       // bottom

            if (j > 0)   sum += in[idx - 1];             // left
            if (j + 1 < N) sum += in[idx + 1];           // right

            out[idx] = sum / 5.0;                       // write result
        }
    }
}
