#pragma once
#include <cmath>
#include <vector>
#include <complex>
#include <algorithm>
#include <omp.h>

#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
//  Optimised in‑place radix‑2 FFT (Cali‑Civita style)
// -----------------------------------------------------------------------------
inline void fft_inline(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // -------------------------------------------------------------------------
    //  1.  Pre‑compute twiddle factors (sine/cosine array)
    // -------------------------------------------------------------------------
    std::vector<std::complex<double>> w(N/2);
    const double theta = M_PI / N;               // π/N
    for (std::size_t k = 0; k < N/2; ++k)
        w[k] = std::complex<double>(std::cos(theta * k), -std::sin(theta * k));

    // -------------------------------------------------------------------------
    //  2.  Butterfly stages (iterative bit‑reversed radix‑2 FFT)
    // -------------------------------------------------------------------------
    for (std::size_t m = 1; m < N; m <<= 1)          // m = 1,2,4,...
    {
        const std::size_t step = m << 1;                     // 2*m
        const std::size_t half = m;
        const std::size_t wstep = N / step;                  // twiddle step

        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += step)
        {
            std::size_t j = 0;
            for (std::size_t k = i; k < i + half; ++k, ++j)
            {
                const std::complex<double> t = w[j * wstep] * x[k + half];
                const std::complex<double> u = x[k];
                x[k]          = u + t;
                x[k + half]   = u - t;
            }
        }
    }

    // -------------------------------------------------------------------------
    //  3.  Bit‑reversal permutation (in‑place, no extra buffer)
    // -------------------------------------------------------------------------
    const int logN = static_cast<int>(std::log2(N));
    for (std::size_t i = 0; i < N; ++i)
    {
        // Compute j = bit‑reverse(i) for logN bits
        std::size_t j = ((i & 0xaaaaaaaa) >> 1) | ((i & 0x55555555) << 1);
        j = ((j & 0xcccccccc) >> 2) | ((j & 0x33333333) << 2);
        j = ((j & 0xf0f0f0f0) >> 4) | ((j & 0x0f0f0f0f) << 4);
        j = ((j & 0xff00ff00) >> 8) | ((j & 0x00ff00ff) << 8);
        j = ((j >> 16) | (j << 16)) >> (32 - logN);

        if (j > i)
            std::swap(x[i], x[j]);       // only swap when i < j to avoid double work
    }
}

// -----------------------------------------------------------------------------
//  In‑place inverse FFT using the forward FFT routine
// -----------------------------------------------------------------------------
inline void ifft(std::vector<std::complex<double>> &x)
{
    // Conjugate the data
    for (auto &v : x) v = std::conj(v);

    // Forward FFT
    fft_inline(x);

    // Conjugate again and scale
    const double invN = 1.0 / static_cast<double>(x.size());
    for (auto &v : x) v = std::conj(v) * invN;
}
