#pragma once
#include <vector>
#include <limits>
#include <omp.h>

/* Replace the i‑th element of the vector x with the minimum value
   from indices 0 through i.
   The implementation performs a parallel inclusive‑scan for the min
   operation using OpenMP and preserves the original behaviour. */
void partialMinimums(std::vector<float> &x) {
    if (x.empty())
        return;

    const size_t n = x.size();

    /* Determine the number of threads. */
    int num_threads;
#pragma omp parallel
    {
#pragma omp single
        num_threads = omp_get_num_threads();
    }

    /* Divide work into roughly equal block size. */
    const size_t chunk = (n + num_threads - 1) / num_threads;

    std::vector<float> local_min(num_threads, std::numeric_limits<float>::max());

    /* 1st pass – compute the minimum of each block independently. */
#pragma omp parallel for schedule(static)
    for (int t = 0; t < num_threads; ++t) {
        size_t start = t * chunk;
        size_t end   = std::min(start + chunk, n);
        float m = std::numeric_limits<float>::max();
        for (size_t i = start; i < end; ++i)
            m = std::min(m, x[i]);
        local_min[t] = m;
    }

    /* Prefix sum over block minima to determine the minimum up to each block. */
    std::vector<float> prefix(num_threads);
    float acc = std::numeric_limits<float>::max();
    for (int t = 0; t < num_threads; ++t) {
        acc = std::min(acc, local_min[t]);   // global min up to the end of this block
        prefix[t] = acc;                     // will be used as starting value for the next block
    }

    /* 2nd pass – compute the inclusive minimum across the entire array.
       Each block starts with the minimum value obtained from the preceding blocks. */
#pragma omp parallel for schedule(static)
    for (int t = 0; t < num_threads; ++t) {
        size_t start = t * chunk;
        size_t end   = std::min(start + chunk, n);
        float m = prefix[t];
        for (size_t i = start; i < end; ++i) {
            m = std::min(m, x[i]);
            x[i] = m;
        }
    }
}
