#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/// Return true if `val` is present in exactly one of the vectors `x` or `y`.
/// The function preserves the original semantics while leveraging
/// parallelism for large containers.
///
/// @param x First input vector.
/// @param y Second input vector.
/// @param val Value to search for.
/// @return true if `val` appears in exactly one of the vectors, false otherwise.
inline bool xorContains(const std::vector<int>& x,
                        const std::vector<int>& y,
                        int val) noexcept
{
    // Fast path: if the vectors are empty we can short‑circuit.
    if (x.empty() && y.empty()) return false;

    // Parallel search in `x`.  `foundX` will be true if `val` occurs in `x`.
    bool foundX = false;
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (!foundX && x[i] == val) {
            #pragma omp atomic write
            foundX = true;
        }
    }

    // If `val` is found in both vectors, we can return false immediately.
    if (foundX) {
        bool foundY = false;
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < y.size(); ++i) {
            if (!foundY && y[i] == val) {
                #pragma omp atomic write
                foundY = true;
            }
        }
        return !foundY;          // true only if `val` is absent in `y`
    }

    // `val` is not in `x`; it must be in `y` for the XOR to be true.
    bool foundY = false;
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        if (!foundY && y[i] == val) {
            #pragma omp atomic write
            foundY = true;
        }
    }
    return foundY;              // true if `val` is present in `y`
}
